    <!-- 公共属性 -->
    <section id="properties" class="ch-section">
      <h2 class="ch-section__title">公共属性</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>readonly id: string</code>
        </h3>
        <p class="api-item__desc">画布唯一标识符（只读）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>readonly selectedCells: Ref&lt;SelectedCell[]&gt;</code>
        </h3>
        <p class="api-item__desc">当前选中的单元格列表（响应式，可直接在 Vue 组件中使用）</p>
      </div>
    </section>

    <!-- Graph 相关 -->
    <section id="graph-api" class="ch-section">
      <h2 class="ch-section__title">Graph 相关</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getGraph(): Graph</code>
        </h3>
        <p class="api-item__desc">获取底层 X6 Graph 实例，用于直接访问 X6 的底层 API</p>
        <div class="api-item__example">
          <pre><code>const graph = designer.getGraph()
graph.on('node:click', ({ node }) => {
  console.log('节点被点击:', node.id)
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getRootNodes(): Node[]</code>
        </h3>
        <p class="api-item__desc">获取画布中的顶层起始节点（入度为 0 的节点），即没有任何连线指向它的节点</p>
        <div class="api-item__example">
          <pre><code>const rootNodes = designer.getRootNodes()
console.log('起始节点:', rootNodes)</code></pre>
        </div>
      </div>
    </section>

    <!-- 状态管理 -->
    <section id="state-api" class="ch-section" v-if="false">
      <h2 class="ch-section__title">状态管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getMeta(): FlowMeta</code>
        </h3>
        <p class="api-item__desc">获取当前流程的元数据（名称、分类、版本等）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>setMeta(meta: Partial&lt;FlowMeta&gt;): void</code>
        </h3>
        <p class="api-item__desc">更新流程元数据</p>
        <div class="api-item__example">
          <pre><code>designer.setMeta({
  name: '新流程名称',
  description: '流程描述'
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>reset(meta?: Partial&lt;FlowMeta&gt;): void</code>
        </h3>
        <p class="api-item__desc">重置流程状态并清空选择</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>isDirty(): boolean</code>
        </h3>
        <p class="api-item__desc">检查画布是否有未保存的更改</p>
      </div>
    </section>

    <!-- 模式与权限 -->
    <section id="mode-api" class="ch-section">
      <h2 class="ch-section__title">模式与权限</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getMode(): DesignerMode</code>
        </h3>
        <p class="api-item__desc">获取当前设计器模式</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>setMode(mode: DesignerMode): void</code>
        </h3>
        <p class="api-item__desc">切换设计器模式（会触发 onModeChange 回调）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>can(capability: keyof ModeCapabilities): boolean</code>
        </h3>
        <p class="api-item__desc">检查当前模式是否有某个权限</p>
        <div class="api-item__example">
          <pre><code>if (designer.can('canDrag')) {
  console.log('允许拖拽')
}</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>hasPermission(key: keyof ModeCapabilities): boolean</code>
        </h3>
        <p class="api-item__desc">检查当前模式是否有某个权限（与 can 等价）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getCurrentPermissions(): ModeCapabilities</code>
        </h3>
        <p class="api-item__desc">获取当前模式的完整权限配置（已合并默认值）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getAllPermissions(): Record&lt;string, ModeCapabilities&gt;</code>
        </h3>
        <p class="api-item__desc">获取所有模式的完整权限配置（包括用户扩展的自定义模式）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getAvailableModes(): string[]</code>
        </h3>
        <p class="api-item__desc">获取所有可用的模式列表</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>updatePermissions(config): void</code>
        </h3>
        <p class="api-item__desc">动态更新权限配置并立即同步到 X6 Graph</p>
        <div class="api-item__example">
          <pre><code>designer.updatePermissions({
  design: { canDrag: true },
  readonly: { canDrag: false }
})</code></pre>
        </div>
      </div>
    </section>

    <!-- 配置管理 -->
    <section id="config-api" class="ch-section">
      <h2 class="ch-section__title">配置管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>getCanvasConfig(): CanvasConfig</code>
        </h3>
        <p class="api-item__desc">获取当前画布的完整配置</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>updateCanvasConfig(update: Partial&lt;CanvasConfig&gt;): void</code>
        </h3>
        <p class="api-item__desc">更新画布配置（支持部分更新）</p>
        <div class="api-item__example">
          <pre><code>designer.updateCanvasConfig({
  grid: { size: 20, visible: true }
})</code></pre>
        </div>
      </div>
    </section>

    <!-- 历史记录 -->
    <section id="history-api" class="ch-section">
      <h2 class="ch-section__title">历史记录</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>undo(): boolean</code>
        </h3>
        <p class="api-item__desc">撤销上一步操作（需要 canUndo 权限）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>redo(): boolean</code>
        </h3>
        <p class="api-item__desc">重做上一步撤销的操作（需要 canRedo 权限）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>canUndo(): boolean</code>
        </h3>
        <p class="api-item__desc">检查是否有可撤销的操作</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>canRedo(): boolean</code>
        </h3>
        <p class="api-item__desc">检查是否有可重做的操作</p>
      </div>
    </section>

    <!-- 数据操作 -->
    <section id="data-api" class="ch-section">
      <h2 class="ch-section__title">数据操作</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>save(): void</code>
        </h3>
        <p class="api-item__desc">保存当前流程数据（触发 onSave 回调）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>load(data: FlowData): void</code>
        </h3>
        <p class="api-item__desc">加载流程数据到画布</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>export(format?: 'json' | 'png' | 'svg'): any</code>
        </h3>
        <p class="api-item__desc">导出画布数据（默认格式为 'json'）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>addCell(cell: Node | Edge, source?: string): Promise&lt;boolean&gt;</code>
        </h3>
        <p class="api-item__desc">安全添加单个单元格（支持 beforeNodeAdd 拦截）</p>
        <div class="api-item__example">
          <pre><code>const node = graph.createNode({
  shape: 'rect',
  x: 100,
  y: 100,
  width: 100,
  height: 60,
  label: '新节点'
})
await designer.addCell(node)</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>removeCell(cell: Node | Edge, source?: string): Promise&lt;boolean&gt;</code>
        </h3>
        <p class="api-item__desc">安全移除单个单元格（支持 beforeNodeRemove/beforeEdgeRemove 拦截）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>startDrag(event: MouseEvent, nodeConfig: Partial&lt;Node.Metadata&gt;): Promise&lt;void&gt;</code>
        </h3>
        <p class="api-item__desc">开始拖拽创建节点（需要 canAddNode 权限）</p>
      </div>
    </section>

    <!-- 视图操作 -->
    <section id="view-api" class="ch-section">
      <h2 class="ch-section__title">视图操作</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>zoom(factor: number): void</code>
        </h3>
        <p class="api-item__desc">增量缩放画布（正数放大，负数缩小）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>zoomTo(scale: number): void</code>
        </h3>
        <p class="api-item__desc">缩放画布到指定比例（1 为 100%）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>fitToContent(padding?: number): void</code>
        </h3>
        <p class="api-item__desc">缩放并居中画布以适应所有内容（默认内边距 40）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>centerContent(): void</code>
        </h3>
        <p class="api-item__desc">居中画布内容（不改变缩放比例）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>resetView(): void</code>
        </h3>
        <p class="api-item__desc">重置视图（缩放到 100% 并居中，需要 canResetView 权限）</p>
      </div>
    </section>

    <!-- 成组功能 -->
    <section id="group-api" class="ch-section">
      <h2 class="ch-section__title">成组功能</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>groupSelectedNodes(): boolean</code>
        </h3>
        <p class="api-item__desc">将选中的节点成组（需要 canGroup 权限，至少选中 2 个有效节点）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>ungroupSelected(): boolean</code>
        </h3>
        <p class="api-item__desc">解组选中的组节点（需要 canGroup 权限）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>canGroup(): boolean</code>
        </h3>
        <p class="api-item__desc">检查当前选中的节点是否可以成组</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>canUngroup(): boolean</code>
        </h3>
        <p class="api-item__desc">检查当前选中的节点是否可以解组</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>toggleGroupCollapse(group: Node): boolean</code>
        </h3>
        <p class="api-item__desc">切换分组节点的展开/收起状态</p>
      </div>
    </section>

    <!-- 节点状态管理 -->
    <section id="node-state-api" class="ch-section">
      <h2 class="ch-section__title">节点状态管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerNodeStateHandler(stateName, handler, override?): void</code>
        </h3>
        <p class="api-item__desc">注册或覆盖全局节点状态处理器</p>
        <div class="api-item__example">
          <pre><code>designer.registerNodeStateHandler('custom', (node, state, context) => {
  node.attr('body/stroke', '#ff0000')
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerNodeStateHandlerForType(nodeType, stateName, handler, override?): void</code>
        </h3>
        <p class="api-item__desc">为特定节点类型注册状态处理器</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>setPortsVisibility(node, visible, style?): void</code>
        </h3>
        <p class="api-item__desc">设置节点锚点的可见性和样式</p>
        <div class="api-item__example">
          <pre><code>// 显示默认样式的锚点
designer.setPortsVisibility(node, true)

// 显示 hover 样式的锚点
designer.setPortsVisibility(node, true, 'hover')</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>setTooltipVisibility(node, visible): void</code>
        </h3>
        <p class="api-item__desc">设置节点 Tooltip 的可见性</p>
      </div>
    </section>

    <!-- 边状态管理 -->
    <section id="edge-state-api" class="ch-section">
      <h2 class="ch-section__title">边状态管理</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>setEdgeLabel(edge, label?, state?): void</code>
        </h3>
        <p class="api-item__desc">设置连线标签（支持状态样式）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>updateEdgeLabelText(edge, label): void</code>
        </h3>
        <p class="api-item__desc">只更新连线标签的文本内容，保持当前样式和状态不变</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerEdgeStateHandler(stateName, handler, override?): void</code>
        </h3>
        <p class="api-item__desc">注册或覆盖全局边状态处理器</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>registerEdgeStateHandlerForType(edgeType, stateName, handler, override?): void</code>
        </h3>
        <p class="api-item__desc">为特定边类型注册状态处理器</p>
      </div>
    </section>

    <!-- 回调注册 -->
    <section id="callbacks" class="ch-section">
      <h2 class="ch-section__title">回调注册</h2>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onSelectionChange(callback): void</code>
        </h3>
        <p class="api-item__desc">注册选中变化回调</p>
        <div class="api-item__example">
          <pre><code>designer.onSelectionChange((cells) => {
  console.log('选中的单元格:', cells)
})</code></pre>
        </div>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onCellAdded(callback): void</code>
        </h3>
        <p class="api-item__desc">注册单元格添加回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onCellRemoved(callback): void</code>
        </h3>
        <p class="api-item__desc">注册单元格删除回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onDirtyChange(callback): void</code>
        </h3>
        <p class="api-item__desc">注册脏状态变化回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onModeChange(callback): void</code>
        </h3>
        <p class="api-item__desc">注册模式变化回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onSave(callback): void</code>
        </h3>
        <p class="api-item__desc">注册保存回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>onError(callback): void</code>
        </h3>
        <p class="api-item__desc">注册错误回调</p>
      </div>
    </section>

    <!-- 生命周期拦截器 -->
    <section id="lifecycle" class="ch-section">
      <h2 class="ch-section__title">生命周期拦截器</h2>
      <p class="ch-section__desc">以下回调在构造函数的 callbacks 参数中传入，用于拦截关键操作：</p>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>beforeNodeAdd?: (node, source) => boolean | Promise&lt;boolean&gt;</code>
        </h3>
        <p class="api-item__desc">节点添加前拦截器（返回 false 阻止添加）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>afterNodeAdd?: (node, source) => void</code>
        </h3>
        <p class="api-item__desc">节点添加后回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>beforeNodeRemove?: (node, source) => boolean | Promise&lt;boolean&gt;</code>
        </h3>
        <p class="api-item__desc">节点删除前拦截器（返回 false 阻止删除）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>afterNodeRemove?: (nodeId, nodeData, source) => void</code>
        </h3>
        <p class="api-item__desc">节点删除后回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>validateConnection?: (params) => boolean</code>
        </h3>
        <p class="api-item__desc">连线验证拦截器（返回 false 阻止连线创建）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>beforeEdgeAdd?: (params) => boolean</code>
        </h3>
        <p class="api-item__desc">连线创建前拦截器（在 validateConnection 阶段调用）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>afterEdgeAdd?: (edge, source) => void</code>
        </h3>
        <p class="api-item__desc">边添加后回调</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>beforeNodeHover?: (event) => boolean</code>
        </h3>
        <p class="api-item__desc">节点 hover 前钩子（返回 false 阻止 hover 效果）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>afterNodeHover?: (event) => void</code>
        </h3>
        <p class="api-item__desc">节点 hover 后钩子</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
          <code>beforeNodeSelect?: (event) => boolean</code>
        </h3>
        <p class="api-item__desc">节点选中前钩子（返回 false 阻止选中）</p>
      </div>

      <div class="api-item">
        <h3 class="api-item__signature">
