<script setup lang="ts">
import GuideLayout from '@/views/guide/components/GuideLayout.vue'
import { onMounted } from 'vue'

let scrollContainer: HTMLElement | null = null

onMounted(() => {
  // 获取滚动容器（GuideLayout 的 main.guide-content 元素）
  scrollContainer = document.querySelector('.guide-content')
})

function scrollToSection(id: string) {
  const el = document.getElementById(id)
  if (el && scrollContainer) {
    // 计算目标元素相对于滚动容器的位置
    const containerRect = scrollContainer.getBoundingClientRect()
    const elementRect = el.getBoundingClientRect()
    const offsetTop = elementRect.top - containerRect.top + scrollContainer.scrollTop
    
    // 滚动到目标位置（留出 20px 上边距）
    scrollContainer.scrollTo({
      top: offsetTop - 20,
      behavior: 'smooth'
    })
  }
}
</script>

